#!/usr/bin/env node
/**
 * Pre-build step: bake CHARCLAW_SERVER_URL into the compiled Electron app.
 *
 * Writes `src/server-url.generated.ts` containing the URL electron-builder
 * will ship. Reads from the CHARCLAW_SERVER_URL env var; defaults to
 * http://localhost:3000 so `npm run build:win` produces a working
 * local-dev installer out of the box.
 *
 * The generated file is gitignored.
 */

import { writeFileSync } from "node:fs"
import { resolve, dirname } from "node:path"
import { fileURLToPath } from "node:url"

const __dirname = dirname(fileURLToPath(import.meta.url))
const url = (process.env.CHARCLAW_SERVER_URL || "http://localhost:3000").trim()

// Basic URL validation so we fail loud in CI, not silently at runtime.
try {
  new URL(url)
} catch {
  console.error(`[bake-server-url] Invalid URL: "${url}"`)
  process.exit(1)
}

const out = resolve(__dirname, "..", "src", "server-url.generated.ts")
const content = `// AUTO-GENERATED by scripts/bake-server-url.mjs — do not edit by hand.
// Overwritten on every build from the CHARCLAW_SERVER_URL env var.
export const BAKED_SERVER_URL = ${JSON.stringify(url)}
`

writeFileSync(out, content, "utf8")
console.log(`[bake-server-url] wrote ${out} -> ${url}`)
